(function(){'use strict';var FORCE_GRAPH_CDN='https://unpkg.com/force-graph';var NODE_SIZE=6;var NODE_COLORS={post:'#4299e1',tag:'#f59e0b',category:'#48bb78'};function getThemeColors(){var isDark=(document.documentElement.getAttribute('data-theme')==='dark'||(!document.documentElement.getAttribute('data-theme')&&window.matchMedia&&window.matchMedia('(prefers-color-scheme: dark)').matches));return{background:isDark?'#1a1a1a':'#ffffff',link:isDark?'#555555':'#cccccc',label:isDark?'#e0e0e0':'#333333'};}
var GRAPH_DATA=window.GRAPH_DATA||{nodes:[],links:[]};var graphInstance=null;var highlightNodes=new Set();var highlightLinks=new Set();var selectedNode=null;function selectNode(node){highlightNodes.clear();highlightLinks.clear();selectedNode=node;if(!node||!graphInstance){return;}
highlightNodes.add(node);graphInstance.graphData().links.forEach(function(link){if(link.source===node||link.target===node){highlightLinks.add(link);highlightNodes.add(link.source);highlightNodes.add(link.target);}});}
function drawNode(node,ctx,globalScale){var hasSelection=highlightNodes.size>0;var isHighlighted=highlightNodes.has(node);var dimmed=hasSelection&&!isHighlighted;var color=NODE_COLORS[node.type]||'#888888';var size=NODE_SIZE;ctx.save();if(dimmed){ctx.globalAlpha=0.15;}
ctx.fillStyle=color;ctx.beginPath();if(node.type==='post'){ctx.rect(node.x-size,node.y-size,size*2,size*2);}else if(node.type==='category'){ctx.moveTo(node.x,node.y-size*1.15);ctx.lineTo(node.x+size,node.y+size*0.7);ctx.lineTo(node.x-size,node.y+size*0.7);ctx.closePath();}else{ctx.arc(node.x,node.y,size,0,Math.PI*2);}
ctx.fill();if(!dimmed&&hasSelection&&isHighlighted){ctx.strokeStyle=(node===selectedNode)?'rgba(255,255,255,0.95)':'rgba(255,255,255,0.55)';ctx.lineWidth=2/globalScale;ctx.stroke();}
if(globalScale>=1.5){var label=node.label||'';var fontSize=10/globalScale;var themeColors=getThemeColors();ctx.font=fontSize+'px Sans-Serif';ctx.textAlign='center';ctx.textBaseline='top';ctx.fillStyle=themeColors.label;if(dimmed){ctx.globalAlpha=0.15;}
ctx.fillText(label,node.x,node.y+size+1/globalScale);}
ctx.restore();}
function paintPointerArea(node,color,ctx){var size=NODE_SIZE;ctx.fillStyle=color;ctx.beginPath();if(node.type==='post'){ctx.rect(node.x-size,node.y-size,size*2,size*2);}else if(node.type==='category'){ctx.moveTo(node.x,node.y-size*1.15);ctx.lineTo(node.x+size,node.y+size*0.7);ctx.lineTo(node.x-size,node.y+size*0.7);ctx.closePath();}else{ctx.arc(node.x,node.y,size,0,Math.PI*2);}
ctx.fill();}
function getLinkColor(link){if(highlightLinks.has(link)){return'rgba(255,255,255,0.8)';}
return getThemeColors().link;}
function getLinkWidth(link){return highlightLinks.has(link)?2:1;}
function getParticleWidth(link){return highlightLinks.has(link)?4:0;}
function initGraph(container){var colors=getThemeColors();var width=container.clientWidth||800;var height=container.clientHeight||500;while(container.firstChild){container.removeChild(container.firstChild);}
highlightNodes.clear();highlightLinks.clear();selectedNode=null;graphInstance=ForceGraph()(container).width(width).height(height).backgroundColor(colors.background).graphData(GRAPH_DATA).nodeId('id').nodeLabel('label').nodeRelSize(NODE_SIZE).nodeCanvasObjectMode(function(){return'replace';}).nodeCanvasObject(drawNode).nodePointerAreaPaint(paintPointerArea).linkColor(getLinkColor).linkWidth(getLinkWidth).linkDirectionalParticles(4).linkDirectionalParticleWidth(getParticleWidth).onNodeClick(function(node){if(selectedNode===node){if(node.url){window.location.href=node.url;}}else{selectNode(node);}}).onBackgroundClick(function(){selectNode(null);}).onNodeDragEnd(function(node){node.fx=node.x;node.fy=node.y;});}
function resizeGraph(){if(!graphInstance){return;}
var container=document.getElementById('graph-container');if(!container){return;}
graphInstance.width(container.clientWidth);graphInstance.height(container.clientHeight);}
function updateGraphColors(){if(!graphInstance){return;}
graphInstance.backgroundColor(getThemeColors().background);}
function setupFullscreenToggle(){var btn=document.getElementById('graph-fullscreen-btn');if(!btn){return;}
btn.addEventListener('click',function(){var active=document.body.classList.toggle('graph-fullscreen-active');btn.setAttribute('aria-pressed',active?'true':'false');setTimeout(resizeGraph,50);});document.addEventListener('keydown',function(e){if(e.key==='Escape'&&document.body.classList.contains('graph-fullscreen-active')){document.body.classList.remove('graph-fullscreen-active');btn.setAttribute('aria-pressed','false');setTimeout(resizeGraph,50);}});}
function loadAndInit(){var container=document.getElementById('graph-container');if(!container){return;}
if(typeof ForceGraph!=='undefined'){initGraph(container);return;}
var script=document.createElement('script');script.src=FORCE_GRAPH_CDN;script.async=true;script.onload=function(){initGraph(container);};script.onerror=function(){container.textContent='Graph could not be loaded. Please check your internet connection.';};document.head.appendChild(script);}
var resizeTimer=null;window.addEventListener('resize',function(){clearTimeout(resizeTimer);resizeTimer=setTimeout(resizeGraph,150);});if(window.MutationObserver){new MutationObserver(function(mutations){mutations.forEach(function(mutation){if(mutation.attributeName==='data-theme'){updateGraphColors();}});}).observe(document.documentElement,{attributes:true});}
setupFullscreenToggle();if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',loadAndInit);}else{loadAndInit();}})();